#!/bin/bash
set -e
cd ~/chaos_tester
echo "=== Deploy v7: Internal revenue filtering + condensed Detailed Results ==="
echo "1/2 ai_visibility.py..." && echo "" | base64 -d > modules/ai_visibility.py
echo "2/2 report.html..." && echo "" | base64 -d > templates/report.html

echo ""
python3 -c "import ast; ast.parse(open('modules/ai_visibility.py').read()); print('Syntax OK')"

echo ""
git add -A
git commit -m "fix: use revenue buckets internally for competitor filtering, condense Detailed Results

- Revenue buckets now used to filter competitors to same/adjacent revenue range
- No revenue data shown to user — only used for intelligent competitor selection
- Detailed Results table shows first 5 rows with expandable scrollable view
- Debug logging for Perplexity API key detection and query flow"

echo ""
echo "Deploying..."
gcloud run deploy chaos-tester \
  --project chaos-tester \
  --source . \
  --region us-central1 \
  --allow-unauthenticated \
  --quiet

echo ""
git push origin main

echo "=== v7 Complete ==="
echo ""
echo "To check if Perplexity API key is working, view logs after a test run:"
echo "  gcloud logging read 'resource.type=cloud_run_revision AND textPayload:AI_VIS' --project chaos-tester --limit 20 --format='value(textPayload)'"
